var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HUNTER_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"큭! 이러다 전복되겠어! 후퇴해!","JPN":"くっ！　このままだと転覆してしまう！　後退しろ！","ENG":"Kgh! The ship's going to turn over! Retreat!","TWN":"唔！這樣下去會全軍覆沒，撤退！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PIRATE_FRONTBAY_NULL_SEVERAL","text":{"KOREA":"두고 보자, 샤크스!","JPN":"覚えておけよ、シャークス！","ENG":"This isn't over, Sharks!","TWN":"走著瞧，大白鯊海盜團！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫- 벌써 전부 나가떨어진 건가? 시시하긴.","JPN":"キャハハッ、もう全部諦めたのか？　つまんないね。","ENG":"Kya hah hah! Are they already gone? Lame.","TWN":"哈哈哈，這麼快就撤退啦？真沒意思。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"꺄하하- 너무 쉬운데요?","JPN":"キャハハッ、簡単すぎますね。","ENG":"Kya hah hah. It's too easy!","TWN":"哈哈哈，得來全不費工夫呢？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"뭔가 이상하지 않아?","JPN":"何かおかしくない？","ENG":"Something's weird.","TWN":"不覺得有些奇怪嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"싸우는 동안 침식체가 하나도 보이지 않았어.","JPN":"戦っている間に侵食体が一匹も出なかった。","ENG":"I didn't see a single C.O. while we were fighting.","TWN":"剛剛和其他人交手的時候，連一隻侵蝕體都沒有看到。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"어라? 그러게요.","JPN":"あれ？　そうですね。","ENG":"Huh? Come to think of it, you're right.","TWN":"喔？說的也是。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저희가 우연히 다 피해서 온 거 아닐까요?","JPN":"私たちが運よく全部避けてきたとか？","ENG":"Maybe we just happened to avoid all of them?","TWN":"會不會是都剛好沒遇到？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"검은 범람이 오면 항상 격벽 주위엔 침식체가 들끓었다고.","JPN":"黒い氾濫が来るといつも隔壁の周りには侵食体がうじゃうじゃいたよ。","ENG":"With the Black Flood, the bulwark should be surrounded by C.O.s.","TWN":"每當發生黑色洪災時，隔離牆周圍總是會佈滿侵蝕體。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그런데 막상 바다 한가운덴 아무것도 없는 게 말이 돼?","JPN":"なのにいざ海のど真ん中には何もないのってありえないだろ？","ENG":"But it doesn't make sense that there's none of them in the middle of the ocean.","TWN":"但現在我們可是在海中央，連一隻侵蝕體都沒有說得過去嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이상하게 생각할 필요 없어. 좋은 게 좋은 거지.","JPN":"深く考える必要はない。結果オーライだ。","ENG":"Don't overthink it. It's a good thing.","TWN":"別胡思亂想，就算我們幸運吧。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이대로 심해역까지 가서 에이버리의 함선을 찾기만 하면 끝…","JPN":"このまま深海域まで行ってエイバリーの艦船を見つけさえすれば終わ……","ENG":"We'll continue on to the deep sea area and find Avery's ship–","TWN":"就這樣去到深海域，找到艾維利的艦船…"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"뭐죠? 배에 뭔가 걸리는 소리가 났는데요?","JPN":"あれ？　船に何か引っかかる音がしましたよ？","ENG":"Huh? Did something get caught on the ship?","TWN":"嗯？好像有什麼東西勾到船？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"배가 멈췄잖아? 해조류에 엉켰나?","JPN":"船が止まった？　海藻が絡まったのか？","ENG":"The ship's stopped. Is it entangled in seaweed or something?","TWN":"船怎麼停啦？是被海草纏住嗎？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"내가 밑으로 가서 확인해볼게.","JPN":"あたしが下に行って見てくる。","ENG":"I'll go down and check.","TWN":"我下去看看。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"네? 소냐, 잠깐만요! 뭐가 있을 줄 알고…!","JPN":"はい？　ソーニャ、待って！　何があるかわからないじゃないですか……！","ENG":"Huh? Sonya, wait! You don't know what's down there...!","TWN":"什麼？索妮雅，等等！下面不知道有什麼…！"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"…수면 아래가 하나도 안 보이는데요? 괜찮을까요?","JPN":"……水面の下が何も見えませんよ？　大丈夫でしょうか？","ENG":"...I can't see anything in the water. Will she be okay?","TWN":"…水下面什麼也看不見？不會出事吧？"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"뭐, 소냐라면 어련히 알아서 해결하겠지.","JPN":"まあ、ソーニャなら何とか解決できるだろう。","ENG":"It's Sonya. She can take care of herself.","TWN":"沒事，索妮雅會自己想辦法的。"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"기왕 이렇게 된 거, 난 누워서 윙스타 근황 중계나…","JPN":"こうなったからには、あたしは寝転んでウィングスターでも……","ENG":"Well, since we're stopping, I'll just lie down and do a live stream on Wing-sta–","TWN":"在她回來之前我就先躺下來滑一下…"},"stage":{"bg":"FRONTBAY_DECK","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};